import logging
import json
import datetime

class JsonFormatter(logging.Formatter):
    RESERVED_ATTRS = {
        'name', 'levelname', 'pathname', 'filename', 'lineno', 'funcName',
        'process', 'processName', 'thread', 'threadName', 'created', 'msecs',
        'relativeCreated', 'asctime', 'message', 'args', 'exc_info',
        'exc_text', 'stack_info', 'levelno', 'msg', 'module',
    }

    def __init__(self, fmt=None, datefmt="%Y-%m-%d %H:%M:%S.%f", style='%', validate=True, json_indent=None):
        super().__init__(fmt, datefmt, style, validate)
        self.json_indent = json_indent

    def format(self, record):
        super().format(record)

        log_entry = {
            "timestamp": record.asctime,
            "level": record.levelname,
            "logger": record.name,
            "message": record.getMessage(),
            "pathname": record.pathname,
            "filename": record.filename,
            "lineno": record.lineno,
            "funcName": record.funcName,
            "process": record.process,
            "processName": record.processName,
            "thread": record.thread,
            "threadName": record.threadName,
        }

        if record.exc_text:
            log_entry["exception"] = record.exc_text

        if record.stack_info:
            log_entry["stack_trace"] = record.stack_info

        for key, value in record.__dict__.items():
            if key not in self.RESERVED_ATTRS and not key.startswith('_'):
                log_entry[key] = value

        try:
            return json.dumps(log_entry, indent=self.json_indent, ensure_ascii=False, default=str)
        except Exception as e:
            fallback_log_entry = {
                "timestamp": datetime.datetime.now().isoformat(timespec='milliseconds'),
                "level": "ERROR",
                "logger": "JsonFormatterError",
                "message": f"Failed to serialize log record to JSON: {e!r}. Original message: {record.getMessage()}",
            }
            try:
                fallback_log_entry["original_log_data"] = str(log_entry)
            except Exception:
                fallback_log_entry["original_log_data"] = "<Unstringifiable original log data>"

            return json.dumps(fallback_log_entry, indent=self.json_indent, ensure_ascii=False)
